UPhysicsAsset* MergePhysicsAssets(USkeletalMesh* MergedSkeletalMesh, const TArray<USkeletalMesh*>& OriginalSkeletalMeshes)
{
    // Create a new Physics Asset for the merged Skeletal Mesh
    UPhysicsAsset* MergedPhysicsAsset = NewObject<UPhysicsAsset>();
    MergedPhysicsAsset->SetSkeletalMesh(MergedSkeletalMesh);

    // Iterate through each original Skeletal Mesh and its Physics Asset
    for (USkeletalMesh* OriginalSkeletalMesh : OriginalSkeletalMeshes)
