            NewBodySetup->BoneName = NewBoneName;
            MergedPhysicsAsset->SkeletalBodySetups.Add(NewBodySetup);
        }

        // Iterate through the constraints in the original Physics Asset
        for (int32 ConstraintIndex = 0; ConstraintIndex < OriginalPhysicsAsset->ConstraintSetup.Num(); ++ConstraintIndex)
        {
            FConstraintInstance NewConstraintInstance = OriginalPhysicsAsset->ConstraintSetup[ConstraintIndex]->DefaultInstance;

            FName OriginalBone1Name = NewConstraintInstance.ConstraintBone1;
            FName OriginalBone2Name = NewConstraintInstance.ConstraintBone2;
            FName NewBone1Name = /* Find corresponding bone name in the merged Skeletal Mesh */;
            FName NewBone2Name = /* Find corresponding bone name in the merged Skeletal Mesh */;

            // Create a new constraint in the merged Physics Asset with the same properties
            NewConstraintInstance.ConstraintBone1 = NewBone1Name;
            NewConstraintInstance.ConstraintBone2 = NewBone2Name;

            UPhysicsConstraintTemplate* NewConstraintSetup = NewObject<UPhysicsConstraintTemplate>();
            NewConstraintSetup->DefaultInstance = NewConstraintInstance;
            MergedPhysicsAsset->ConstraintSetup.Add(NewConstraintSetup);
        }
