#include <stdio.h>
#include <stdlib.h>
#include <time.h>

// Initialize an artificial neuron with random weights and bias
void init_neuron(Neuron *neuron, int num_inputs) {
  // Allocate memory for weights
  neuron->weights = (double *) malloc(num_inputs * sizeof(double));

  // Initialize weights with random values
  for (int i = 0; i < num_inputs; i++) {
    neuron->weights[i] = (double) rand() / RAND_MAX;
  }

  // Initialize bias with random value
  neuron->bias = (double) rand() / RAND_MAX;

  // Initialize output and delta to zero
  neuron->output = 0.0;
  neuron->delta = 0.0;
}

// Initialize a layer of artificial neurons with random model parameters
void init_layer(Layer *layer, int num_inputs, int num_neurons) {
  // Allocate memory for neurons
  layer->neurons = (Neuron *) malloc(num_neurons * sizeof(Neuron));

  // Initialize each neuron in the layer
  for (int i = 0; i < num_neurons; i++) {
    init_neuron(&layer->neurons[i], num_inputs);
  }

  // Set number of neurons in the layer
  layer->num_neurons = num_neurons;
}

// Initialize an MLP with random model parameters
void init_mlp(MLP *mlp, int num_inputs, int num_outputs, int num_hidden_layers, int *hidden_layer_sizes) {
  // Seed random number generator
  srand(time(NULL));

  // Allocate memory for layers
