    { name: 'Alice', connections: ['Bob', 'Charlie'] },
    { name: 'Bob', connections: ['Charlie'] },
    { name: 'Charlie', connections: ['Dave'] },
    { name: 'Dave', connections: [] }
];
console.log(findPath(users, 'Alice', 'Dave'));
```
