#include <Servo.h>
#include <SoftwareSerial.h>

const int fanPin = 9;
const int lampPin = 10;
const int servoPin = 11;
const int pumpPin = 12;
const int valvePin = 13;
const int temperatureSensorPin = A0;
const int soilMoistureSensorPin = A1;

Servo servo;
SoftwareSerial btSerial(7, 8);
char receivedChar;

const int temperatureSetpoint = 25;
const int soilMoistureSetpoint = 400;

void setup() {
  pinMode(fanPin, OUTPUT);
  pinMode(lampPin, OUTPUT);
  pinMode(pumpPin, OUTPUT);
  pinMode(valvePin, OUTPUT);
  pinMode(temperatureSensorPin, INPUT);
  pinMode(soilMoistureSensorPin, INPUT);

  servo.attach(servoPin);
  btSerial.begin(9600);
  Serial.begin(9600);
}

void loop() {
  int temperature = analogRead(temperatureSensorPin);
  int soilMoisture = analogRead(soilMoistureSensorPin);

  if (temperature > temperatureSetpoint) {
    digitalWrite(fanPin, HIGH);
    servo.write(180);
  } else {
    digitalWrite(fanPin, LOW);
    servo.write(0);
  }

  if (soilMoisture < soilMoistureSetpoint) {
    digitalWrite(lampPin, HIGH);
    digitalWrite(pumpPin, HIGH);
    digitalWrite(valvePin, HIGH);
  } else {
    digitalWrite(lampPin, LOW);
    digitalWrite(pumpPin, LOW);
    digitalWrite(valvePin, LOW);
  }

  if (btSerial.available()) {
    receivedChar = btSerial.read();
    if (receivedChar == 'F') {
      digitalWrite(fanPin, HIGH);
    } else if (receivedChar == 'f') {
      digitalWrite(fanPin, LOW);
    } else if (receivedChar == 'L') {
      digitalWrite(lampPin, HIGH);
    } else if (receivedChar == 'l') {
      digitalWrite(lampPin, LOW);
    } else if (receivedChar == 'P') {
      digitalWrite(pumpPin, HIGH);
      digitalWrite(valvePin, HIGH);
    } else if (receivedChar == 'p') {
      digitalWrite(pumpPin, LOW);
      digitalWrite(valvePin, LOW);
    }
  }
}
