To use CloudKit in your app, you will need to set up a CloudKit container in the Apple Developer portal and enable CloudKit in your Xcode project. Once you have set up CloudKit, you can use the `CloudKitService` class to interact with your CloudKit database.

Here is an example of how you could implement the `CloudKitService` class:
```swift
import CloudKit

class CloudKitService {
    let container: CKContainer

    init(containerIdentifier: String) {
        container = CKContainer(identifier: containerIdentifier)
    }

    func fetchUsers(completion: @escaping ([CKRecord]?, Error?) -> Void) {
        let predicate = NSPredicate(value: true)
        let query = CKQuery(recordType: "User", predicate: predicate)
        let sortDescriptor = NSSortDescriptor(key: "name", ascending: true)
        query.sortDescriptors = [sortDescriptor]

        let database = container.publicCloudDatabase

        database.perform(query, inZoneWith: nil) { records, error in
            completion(records, error)
        }
    }

    func saveUser(_ user: User, completion: @escaping (CKRecord?, Error?) -> Void) {
        let record = user.toCKRecord()
        let database = container.publicCloudDatabase

        database.save(record) { savedRecord, error in
            completion(savedRecord, error)
        }
    }
