```C#
using System;
using System.Drawing;
using System.Windows.Forms;

namespace DrawCircleAndOctagon
{
    public partial class Form1 : Form
    {
        private Graphics graphics;
        private readonly int radius = 150;

        public Form1()
        {
            InitializeComponent();
            graphics = CreateGraphics();
            drawCircle();
        }

        private void drawCircle()
        {
            graphics.DrawEllipse(new Pen(Color.Black), new Rectangle(ClientRectangle.Width / 2 - radius, ClientRectangle.Height / 2 - radius, radius * 2, radius * 2));
        }

        private void drawOctagon(int centerX, int centerY, int radius)
        {
            Point[] points = new Point[8];
            double angle = Math.PI / 4;
            for (int i = 0; i < 8; i++)
            {
                int x = (int)(centerX + radius * Math.Cos(angle + i * Math.PI / 4));
                int y = (int)(centerY + radius * Math.Sin(angle + i * Math.PI / 4));
                points[i] = new Point(x, y);
            }
            graphics.DrawPolygon(new Pen(Color.Black), points);
        }

        private void wander()
        {
            for (int i = 0; i < 360; i++)
            {
                graphics.Clear(BackColor);
                double angle = i * Math.PI / 180;
                int x = (int)(radius * Math.Cos(angle));
                int y = (int)(radius * Math.Sin(angle));
                drawOctagon(ClientRectangle.Width / 2 + x / 2, ClientRectangle.Height / 2 + y / 2, radius / 2);
                drawCircle();
            }
        }

        private void Form1_Paint(object sender, PaintEventArgs e)
        {
            wander();
        }
    }
}
```
